1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should preserve a block pattern [(0,0),(1,0),(0,1),(1,1)] as still life", () => {
15	    const input: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const sortCells = (cells: Array<[number, number]>) =>
17	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
18	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(input));
19	  });
20	  it("should transform a vertical blinker [(0,0),(0,1),(0,2)] into a horizontal blinker [(-1,1),(0,1),(1,1)]", () => {
21	    const input: Array<[number, number]> = [[0, 0], [0, 1], [0, 2]];
22	    const expected: Array<[number, number]> = [[-1, 1], [0, 1], [1, 1]];
23	    const sortCells = (cells: Array<[number, number]>) =>
24	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
25	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(expected));
26	  });
27	  it("should kill a live cell with 4 live neighbors (overpopulation)", () => {
28	    const input: Array<[number, number]> = [[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]];
29	    const result = nextGeneration(input);
30	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(false);
31	  });
32	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
33	    const input: Array<[number, number]> = [[0, 0], [1, 0], [0, 1]];
34	    const result = nextGeneration(input);
35	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(true);
36	  });
37	  it.todo("should handle negative coordinates correctly");
38	});
39

1	type Cell = [number, number];
2	
3	const neighborOffsets: Array<Cell> = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0],           [1, 0],
6	  [-1, 1],  [0, 1],  [1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	const survives = (currentlyAlive: boolean, liveNeighborCount: number): boolean =>
12	  (currentlyAlive && liveNeighborCount === 2) || liveNeighborCount === 3;
13	
14	export const nextGeneration = (liveCells: Array<Cell>): Array<Cell> => {
15	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
16	  const isAlive = (x: number, y: number): boolean => liveSet.has(cellKey(x, y));
17	
18	  const countLiveNeighbors = (x: number, y: number): number =>
19	    neighborOffsets.reduce(
20	      (count, [dx, dy]) => count + (isAlive(x + dx, y + dy) ? 1 : 0),
21	      0,
22	    );
23	
24	  const candidates = new Map<string, Cell>();
25	  const considerCell = (x: number, y: number): void => {
26	    candidates.set(cellKey(x, y), [x, y]);
27	  };
28	  for (const [x, y] of liveCells) {
29	    considerCell(x, y);
30	    for (const [dx, dy] of neighborOffsets) {
31	      considerCell(x + dx, y + dy);
32	    }
33	  }
34	
35	  return [...candidates.values()].filter(([x, y]) =>
36	    survives(isAlive(x, y), countLiveNeighbors(x, y)),
37	  );
38	};
